import React, { useState } from 'react';
import {
  Stepper,
  Step,
  StepLabel,
  Button,
  Typography,
  Box,
  TextField,
  Grid,
  Paper,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Chip,
  IconButton,
  Alert,
} from '@mui/material';
import {
  Add as AddIcon,
  Delete as DeleteIcon,
  Save as SaveIcon,
  Send as SendIcon,
} from '@mui/icons-material';
import { useForm, Controller, useFieldArray } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';

const formSchema = z.object({
  personalInfo: z.object({
    firstName: z.string().min(1, 'First name is required'),
    lastName: z.string().min(1, 'Last name is required'),
    email: z.string().email('Invalid email address'),
    phone: z.string().min(10, 'Phone number must be at least 10 digits'),
    currentCompany: z.string().optional(),
    currentPosition: z.string().optional(),
  }),
  education: z.array(z.object({
    institution: z.string().min(1, 'Institution is required'),
    degree: z.string().min(1, 'Degree is required'),
    field: z.string().min(1, 'Field is required'),
    startDate: z.string().min(1, 'Start date is required'),
    endDate: z.string().optional(),
    current: z.boolean().default(false),
  })),
  experience: z.array(z.object({
    company: z.string().min(1, 'Company is required'),
    position: z.string().min(1, 'Position is required'),
    startDate: z.string().min(1, 'Start date is required'),
    endDate: z.string().optional(),
    current: z.boolean().default(false),
    description: z.string().min(1, 'Description is required'),
  })),
  skills: z.array(z.string()).min(1, 'At least one skill is required'),
  resume: z.instanceof(File).optional(),
  coverLetter: z.string().min(1, 'Cover letter is required'),
  availability: z.string().min(1, 'Availability is required'),
});

type FormData = z.infer<typeof formSchema>;

interface JobApplicationFormProps {
  jobId: string;
  onSuccess: () => void;
  onCancel: () => void;
}

const JobApplicationForm: React.FC<JobApplicationFormProps> = ({ jobId, onSuccess, onCancel }) => {
  const [activeStep, setActiveStep] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const {
    control,
    handleSubmit,
    formState: { errors },
    getValues,
    watch,
  } = useForm<FormData>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      personalInfo: {
        firstName: '',
        lastName: '',
        email: '',
        phone: '',
        currentCompany: '',
        currentPosition: '',
      },
      education: [],
      experience: [],
      skills: [],
      coverLetter: '',
      availability: '',
    },
  });

  const {
    fields: educationFields,
    append: appendEducation,
    remove: removeEducation,
  } = useFieldArray({
    control,
    name: 'education',
  });

  const {
    fields: experienceFields,
    append: appendExperience,
    remove: removeExperience,
  } = useFieldArray({
    control,
    name: 'experience',
  });

  const steps = [
    'Personal Information',
    'Education & Experience',
    'Skills & Documents',
    'Review & Submit',
  ];

  const handleNext = () => {
    setActiveStep((prevStep) => prevStep + 1);
  };

  const handleBack = () => {
    setActiveStep((prevStep) => prevStep - 1);
  };

  const onSubmit = async (data: FormData) => {
    try {
      setIsSubmitting(true);
      setError(null);

      const formData = new FormData();
      Object.entries(data).forEach(([key, value]) => {
        if (key === 'resume' && value) {
          formData.append('resume', value);
        } else if (typeof value === 'object') {
          formData.append(key, JSON.stringify(value));
        } else {
          formData.append(key, value as string);
        }
      });

      await axios.post(`/api/jobs/${jobId}/apply`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });

      onSuccess();
    } catch (err) {
      setError('Failed to submit application. Please try again.');
      console.error('Application submission error:', err);
    } finally {
      setIsSubmitting(false);
    }
  };

  const renderStepContent = (step: number) => {
    switch (step) {
      case 0:
        return (
          <Grid container spacing={3}>
            <Grid item xs={12} sm={6}>
              <Controller
                name="personalInfo.firstName"
                control={control}
                render={({ field }) => (
                  <TextField
                    {...field}
                    label="First Name"
                    fullWidth
                    error={!!errors.personalInfo?.firstName}
                    helperText={errors.personalInfo?.firstName?.message}
                  />
                )}
              />
            </Grid>
            <Grid item xs={12} sm={6}>
              <Controller
                name="personalInfo.lastName"
                control={control}
                render={({ field }) => (
                  <TextField
                    {...field}
                    label="Last Name"
                    fullWidth
                    error={!!errors.personalInfo?.lastName}
                    helperText={errors.personalInfo?.lastName?.message}
                  />
                )}
              />
            </Grid>
            <Grid item xs={12}>
              <Controller
                name="personalInfo.email"
                control={control}
                render={({ field }) => (
                  <TextField
                    {...field}
                    label="Email"
                    type="email"
                    fullWidth
                    error={!!errors.personalInfo?.email}
                    helperText={errors.personalInfo?.email?.message}
                  />
                )}
              />
            </Grid>
            <Grid item xs={12}>
              <Controller
                name="personalInfo.phone"
                control={control}
                render={({ field }) => (
                  <TextField
                    {...field}
                    label="Phone"
                    fullWidth
                    error={!!errors.personalInfo?.phone}
                    helperText={errors.personalInfo?.phone?.message}
                  />
                )}
              />
            </Grid>
            <Grid item xs={12} sm={6}>
              <Controller
                name="personalInfo.currentCompany"
                control={control}
                render={({ field }) => (
                  <TextField
                    {...field}
                    label="Current Company"
                    fullWidth
                  />
                )}
              />
            </Grid>
            <Grid item xs={12} sm={6}>
              <Controller
                name="personalInfo.currentPosition"
                control={control}
                render={({ field }) => (
                  <TextField
                    {...field}
                    label="Current Position"
                    fullWidth
                  />
                )}
              />
            </Grid>
          </Grid>
        );

      case 1:
        return (
          <Box>
            <Typography variant="h6" gutterBottom>
              Education
            </Typography>
            {educationFields.map((field, index) => (
              <Paper key={field.id} sx={{ p: 2, mb: 2 }}>
                <Grid container spacing={2}>
                  <Grid item xs={12} sm={6}>
                    <Controller
                      name={`education.${index}.institution`}
                      control={control}
                      render={({ field }) => (
                        <TextField
                          {...field}
                          label="Institution"
                          fullWidth
                          error={!!errors.education?.[index]?.institution}
                          helperText={errors.education?.[index]?.institution?.message}
                        />
                      )}
                    />
                  </Grid>
                  <Grid item xs={12} sm={6}>
                    <Controller
                      name={`education.${index}.degree`}
                      control={control}
                      render={({ field }) => (
                        <TextField
                          {...field}
                          label="Degree"
                          fullWidth
                          error={!!errors.education?.[index]?.degree}
                          helperText={errors.education?.[index]?.degree?.message}
                        />
                      )}
                    />
                  </Grid>
                  <Grid item xs={12} sm={6}>
                    <Controller
                      name={`education.${index}.field`}
                      control={control}
                      render={({ field }) => (
                        <TextField
                          {...field}
                          label="Field of Study"
                          fullWidth
                          error={!!errors.education?.[index]?.field}
                          helperText={errors.education?.[index]?.field?.message}
                        />
                      )}
                    />
                  </Grid>
                  <Grid item xs={12} sm={3}>
                    <Controller
                      name={`education.${index}.startDate`}
                      control={control}
                      render={({ field }) => (
                        <TextField
                          {...field}
                          label="Start Date"
                          type="date"
                          fullWidth
                          InputLabelProps={{ shrink: true }}
                          error={!!errors.education?.[index]?.startDate}
                          helperText={errors.education?.[index]?.startDate?.message}
                        />
                      )}
                    />
                  </Grid>
                  <Grid item xs={12} sm={3}>
                    <Controller
                      name={`education.${index}.endDate`}
                      control={control}
                      render={({ field }) => (
                        <TextField
                          {...field}
                          label="End Date"
                          type="date"
                          fullWidth
                          InputLabelProps={{ shrink: true }}
                          disabled={watch(`education.${index}.current`)}
                        />
                      )}
                    />
                  </Grid>
                  <Grid item xs={12}>
                    <Controller
                      name={`education.${index}.current`}
                      control={control}
                      render={({ field }) => (
                        <FormControl>
                          <InputLabel>Current</InputLabel>
                          <Select
                            {...field}
                            label="Current"
                            onChange={(e) => field.onChange(e.target.value === 'true')}
                            value={field.value ? 'true' : 'false'}
                          >
                            <MenuItem value="true">Yes</MenuItem>
                            <MenuItem value="false">No</MenuItem>
                          </Select>
                        </FormControl>
                      )}
                    />
                  </Grid>
                  <Grid item xs={12}>
                    <IconButton
                      onClick={() => removeEducation(index)}
                      color="error"
                    >
                      <DeleteIcon />
                    </IconButton>
                  </Grid>
                </Grid>
              </Paper>
            ))}
            <Button
              startIcon={<AddIcon />}
              onClick={() => appendEducation({
                institution: '',
                degree: '',
                field: '',
                startDate: '',
                endDate: '',
                current: false,
              })}
            >
              Add Education
            </Button>

            <Typography variant="h6" sx={{ mt: 4, mb: 2 }}>
              Experience
            </Typography>
            {experienceFields.map((field, index) => (
              <Paper key={field.id} sx={{ p: 2, mb: 2 }}>
                <Grid container spacing={2}>
                  <Grid item xs={12} sm={6}>
                    <Controller
                      name={`experience.${index}.company`}
                      control={control}
                      render={({ field }) => (
                        <TextField
                          {...field}
                          label="Company"
                          fullWidth
                          error={!!errors.experience?.[index]?.company}
                          helperText={errors.experience?.[index]?.company?.message}
                        />
                      )}
                    />
                  </Grid>
                  <Grid item xs={12} sm={6}>
                    <Controller
                      name={`experience.${index}.position`}
                      control={control}
                      render={({ field }) => (
                        <TextField
                          {...field}
                          label="Position"
                          fullWidth
                          error={!!errors.experience?.[index]?.position}
                          helperText={errors.experience?.[index]?.position?.message}
                        />
                      )}
                    />
                  </Grid>
                  <Grid item xs={12} sm={3}>
                    <Controller
                      name={`experience.${index}.startDate`}
                      control={control}
                      render={({ field }) => (
                        <TextField
                          {...field}
                          label="Start Date"
                          type="date"
                          fullWidth
                          InputLabelProps={{ shrink: true }}
                          error={!!errors.experience?.[index]?.startDate}
                          helperText={errors.experience?.[index]?.startDate?.message}
                        />
                      )}
                    />
                  </Grid>
                  <Grid item xs={12} sm={3}>
                    <Controller
                      name={`experience.${index}.endDate`}
                      control={control}
                      render={({ field }) => (
                        <TextField
                          {...field}
                          label="End Date"
                          type="date"
                          fullWidth
                          InputLabelProps={{ shrink: true }}
                          disabled={watch(`experience.${index}.current`)}
                        />
                      )}
                    />
                  </Grid>
                  <Grid item xs={12}>
                    <Controller
                      name={`experience.${index}.current`}
                      control={control}
                      render={({ field }) => (
                        <FormControl>
                          <InputLabel>Current</InputLabel>
                          <Select
                            {...field}
                            label="Current"
                            onChange={(e) => field.onChange(e.target.value === 'true')}
                            value={field.value ? 'true' : 'false'}
                          >
                            <MenuItem value="true">Yes</MenuItem>
                            <MenuItem value="false">No</MenuItem>
                          </Select>
                        </FormControl>
                      )}
                    />
                  </Grid>
                  <Grid item xs={12}>
                    <Controller
                      name={`experience.${index}.description`}
                      control={control}
                      render={({ field }) => (
                        <TextField
                          {...field}
                          label="Description"
                          multiline
                          rows={4}
                          fullWidth
                          error={!!errors.experience?.[index]?.description}
                          helperText={errors.experience?.[index]?.description?.message}
                        />
                      )}
                    />
                  </Grid>
                  <Grid item xs={12}>
                    <IconButton
                      onClick={() => removeExperience(index)}
                      color="error"
                    >
                      <DeleteIcon />
                    </IconButton>
                  </Grid>
                </Grid>
              </Paper>
            ))}
            <Button
              startIcon={<AddIcon />}
              onClick={() => appendExperience({
                company: '',
                position: '',
                startDate: '',
                endDate: '',
                current: false,
                description: '',
              })}
            >
              Add Experience
            </Button>
          </Box>
        );

      case 2:
        return (
          <Grid container spacing={3}>
            <Grid item xs={12}>
              <Controller
                name="skills"
                control={control}
                render={({ field }) => (
                  <TextField
                    {...field}
                    label="Skills"
                    fullWidth
                    helperText="Type a skill and press Enter"
                    onKeyDown={(e) => {
                      if (e.key === 'Enter' && field.value) {
                        e.preventDefault();
                        const newSkill = (e.target as HTMLInputElement).value.trim();
                        if (newSkill && !field.value.includes(newSkill)) {
                          field.onChange([...field.value, newSkill]);
                          (e.target as HTMLInputElement).value = '';
                        }
                      }
                    }}
                    error={!!errors.skills}
                    helperText={errors.skills?.message}
                  />
                )}
              />
              <Box sx={{ mt: 2 }}>
                {watch('skills')?.map((skill, index) => (
                  <Chip
                    key={index}
                    label={skill}
                    onDelete={() => {
                      const newSkills = [...watch('skills')];
                      newSkills.splice(index, 1);
                      control.setValue('skills', newSkills);
                    }}
                    sx={{ m: 0.5 }}
                  />
                ))}
              </Box>
            </Grid>
            <Grid item xs={12}>
              <Controller
                name="resume"
                control={control}
                render={({ field: { value, onChange, ...field } }) => (
                  <TextField
                    {...field}
                    type="file"
                    fullWidth
                    onChange={(e) => {
                      const file = (e.target as HTMLInputElement).files?.[0];
                      if (file) {
                        onChange(file);
                      }
                    }}
                    InputLabelProps={{ shrink: true }}
                  />
                )}
              />
            </Grid>
            <Grid item xs={12}>
              <Controller
                name="coverLetter"
                control={control}
                render={({ field }) => (
                  <TextField
                    {...field}
                    label="Cover Letter"
                    multiline
                    rows={6}
                    fullWidth
                    error={!!errors.coverLetter}
                    helperText={errors.coverLetter?.message}
                  />
                )}
              />
            </Grid>
            <Grid item xs={12}>
              <Controller
                name="availability"
                control={control}
                render={({ field }) => (
                  <TextField
                    {...field}
                    label="Availability"
                    fullWidth
                    error={!!errors.availability}
                    helperText={errors.availability?.message}
                  />
                )}
              />
            </Grid>
          </Grid>
        );

      case 3:
        return (
          <Box>
            <Typography variant="h6" gutterBottom>
              Review Your Application
            </Typography>
            <Paper sx={{ p: 3, mb: 3 }}>
              <Typography variant="subtitle1" gutterBottom>
                Personal Information
              </Typography>
              <Typography>
                {getValues('personalInfo.firstName')} {getValues('personalInfo.lastName')}
              </Typography>
              <Typography>{getValues('personalInfo.email')}</Typography>
              <Typography>{getValues('personalInfo.phone')}</Typography>
            </Paper>

            <Paper sx={{ p: 3, mb: 3 }}>
              <Typography variant="subtitle1" gutterBottom>
                Education
              </Typography>
              {getValues('education').map((edu, index) => (
                <Box key={index} sx={{ mb: 2 }}>
                  <Typography variant="subtitle2">
                    {edu.institution} - {edu.degree} in {edu.field}
                  </Typography>
                  <Typography>
                    {edu.startDate} - {edu.current ? 'Present' : edu.endDate}
                  </Typography>
                </Box>
              ))}
            </Paper>

            <Paper sx={{ p: 3, mb: 3 }}>
              <Typography variant="subtitle1" gutterBottom>
                Experience
              </Typography>
              {getValues('experience').map((exp, index) => (
                <Box key={index} sx={{ mb: 2 }}>
                  <Typography variant="subtitle2">
                    {exp.position} at {exp.company}
                  </Typography>
                  <Typography>
                    {exp.startDate} - {exp.current ? 'Present' : exp.endDate}
                  </Typography>
                  <Typography>{exp.description}</Typography>
                </Box>
              ))}
            </Paper>

            <Paper sx={{ p: 3, mb: 3 }}>
              <Typography variant="subtitle1" gutterBottom>
                Skills
              </Typography>
              <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                {getValues('skills').map((skill, index) => (
                  <Chip key={index} label={skill} />
                ))}
              </Box>
            </Paper>

            <Paper sx={{ p: 3, mb: 3 }}>
              <Typography variant="subtitle1" gutterBottom>
                Cover Letter
              </Typography>
              <Typography>{getValues('coverLetter')}</Typography>
            </Paper>

            <Paper sx={{ p: 3 }}>
              <Typography variant="subtitle1" gutterBottom>
                Availability
              </Typography>
              <Typography>{getValues('availability')}</Typography>
            </Paper>
          </Box>
        );

      default:
        return null;
    }
  };

  return (
    <Box sx={{ width: '100%' }}>
      <Stepper activeStep={activeStep} alternativeLabel>
        {steps.map((label) => (
          <Step key={label}>
            <StepLabel>{label}</StepLabel>
          </Step>
        ))}
      </Stepper>

      <Box sx={{ mt: 4 }}>
        {error && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {error}
          </Alert>
        )}

        {renderStepContent(activeStep)}

        <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 4 }}>
          <Button
            disabled={activeStep === 0}
            onClick={handleBack}
          >
            Back
          </Button>
          <Box>
            <Button
              variant="contained"
              onClick={activeStep === steps.length - 1 ? handleSubmit(onSubmit) : handleNext}
              disabled={isSubmitting}
              startIcon={activeStep === steps.length - 1 ? <SendIcon /> : undefined}
            >
              {activeStep === steps.length - 1 ? 'Submit' : 'Next'}
            </Button>
            <Button
              sx={{ ml: 2 }}
              onClick={onCancel}
            >
              Cancel
            </Button>
          </Box>
        </Box>
      </Box>
    </Box>
  );
};

export default JobApplicationForm;
